-- globalCodeInfo :: Either String CodeInfo
-- globalCodeInfo = eitherDecode ["", "Vehicle", "/* pragma solidity ^0.4.8; */\n\n//import \"../../common/Util.sol\";\n/**\n * Util contract\n */\ncontract Util {\n  function stringToBytes32(string memory source) returns (bytes32 result) {\n      assembly {\n          result := mload(add(source, 32))\n      }\n  }\n\n  function b32(string memory source) returns (bytes32) {\n    return stringToBytes32(source);\n  }\n\n  function uintToString(uint i) returns (string){\n      if (i == 0) return \"0\";\n      uint j = i;\n      uint length;\n      while (j != 0){\n          length++;\n          j /= 10;\n      }\n      bytes memory bstr = new bytes(length);\n      uint k = length - 1;\n      while (i != 0){\n          bstr[k--] = byte(48 + i % 10);\n          i /= 10;\n      }\n      return string(bstr);\n  }\n}\n\n\n//import \"../../common/ErrorCodes.sol\";\ncontract ErrorCodes {\n\n    enum ErrorCodes {\n        NULL, \n        SUCCESS, \n        ERROR, \n        NOT_FOUND, \n        EXISTS, \n        RECURSIVE, \n        INSUFFICIENT_BALANCE, \n        UNAUTHORIZED\n    }\n}\n\n\n//import \"./VehicleHistoryEventTypes.sol\";\n/* pragma solidity ^0.4.8; */\n\n\n/**\n * Contract contains constant values for History Snapshot events\n */\ncontract VehicleHistoryEventTypes {\n\n  // Snapshot Events - Constants\n  string constructorEvent = 'constructor';\n  string setTitleEvent = 'title';\n  string addLienHolderEvent = 'addLienHolder';\n  string removeLienHolderEvent = 'removeLienHolder';\n  string addOwnerEvent = 'addOwner';\n  string removeOwnerEvent = 'removeOwner';\n  string updateVehicleTypeEvent = 'updateVehicle-vtype';\n  string updateVehicleYearEvent = 'updateVehicle-year';\n  string updateVehicleMakeEvent = 'updateVehicle-make';\n  string updateVehicleModelEvent = 'updateVehicle-model';\n  string updateVehicleStyleEvent = 'updateVehicle-style';\n  string updateVehicleColorEvent = 'updateVehicle-color';\n  string updateVehicleNumberEvent = 'updateVehicle-number';\n  string pendingAddLienHolderEvent = 'pendingAddLienHolder';\n  string pendingRemoveLienHolderEvent = 'pendingRemoveLienHolder';\n  string updateReasonsEvent = 'updateReasons';\n\n  // Functon to set SnapShot Event defaul values\n  function setSnapshotConstants() internal {\n    // FIXME - pending STRATO-797 - all these presets should be removed\n    constructorEvent = 'constructor';\n    setTitleEvent = 'title';\n    addLienHolderEvent = 'addLienHolder';\n    removeLienHolderEvent = 'removeLienHolder';\n    addOwnerEvent = 'addOwner';\n    removeOwnerEvent = 'removeOwner';\n    updateVehicleTypeEvent = 'updateVehicle-vtype';\n    updateVehicleYearEvent = 'updateVehicle-year';\n    updateVehicleMakeEvent = 'updateVehicle-make';\n    updateVehicleModelEvent = 'updateVehicle-model';\n    updateVehicleStyleEvent = 'updateVehicle-style';\n    updateVehicleColorEvent = 'updateVehicle-color';\n    updateVehicleNumberEvent = 'updateVehicle-number';\n    pendingAddLienHolderEvent = 'pendingAddLienHolder';\n    pendingRemoveLienHolderEvent = 'pendingRemoveLienHolder';\n    updateReasonsEvent = 'updateReasons';\n  }\n}\n\n\n\n/**\n * Vehicle root\n */\ncontract Vehicle is ErrorCodes, Util, VehicleHistoryEventTypes {\n  uint public timestamp;\n  // creator of the contract\n  int public updateCounter = -1;\n\n  // vehcile info\n  string public vin;\n  string public vtype;\n  string public year;\n  string public make;\n  string public model;\n  string public style;\n  string public color;\n  // title info\n  uint number;\n  uint issueDate;\n  // lienHolders Max Limit\n  uint lhMaxLimit;\n  // owners Max Limit\n  uint ownerMaxLimit;\n  // Place Holder for pending removeLineHolder\n  int internal pendingRemoveLienHolderIndex;\n  // Place Holder for pending addLineHolder\n  int internal pendingAddLienHolderNumber;\n\n  // Lien Holders\n  struct LienHolder {\n    uint number;\n    string hash;\n  }\n  LienHolder[] lienHolders;\n\n  struct Owner {\n    uint number;\n    string hash;\n  }\n  Owner[] owners;\n\n  function Vehicle(\n    string _vin, \n    string _vtype, \n    string _year, \n    string _make, \n    string _model, \n    string _style, \n    string _color\n    ) public {\n    // validate vin\n    if (bytes(_vin).length == 0) {\n      throw;\n    }\n    timestamp = block.timestamp;\n    vin = _vin;\n    vtype = _vtype;\n    year = _year;\n    make = _make;\n    model = _model;\n    style = _style;\n    color = _color;\n    // Lien Holders max limit\n    lhMaxLimit = 4; // FIXME STRATO-797\n    // Owners max limit\n    ownerMaxLimit = 2; // FIXME STRATO-797\n    // set snapshot event constants\n    // function defined in VehicleHistoryEventTypes.sol\n    setSnapshotConstants();\n    // snapshot\n    addSnapshot(constructorEvent, '');\n    pendingRemoveLienHolderIndex = -1; //FIXME STRATO-797\n    pendingAddLienHolderNumber = -1;\n    number = 0;\n    updateCounter = 0; // search hook\n  }\n\n  function setTitle(\n    uint _number, \n    uint _issueDate, \n    uint _lienHolderNumber0, \n    string _lienHolderHash0, \n    uint _ownerNumber0, \n    string _ownerHash0\n  ) public returns (ErrorCodes, int) {\n    // if title exists - prevent overwrite\n    if (number != 0) {\n      return(ErrorCodes.INSUFFICIENT_BALANCE, -1);\n    }\n    // validate owner\n    var ownerErrorCode = validateOwner(_ownerNumber0, _ownerHash0);\n    if (ownerErrorCode != ErrorCodes.SUCCESS) return (ownerErrorCode, -1);\n    // title\n    number = _number;\n    issueDate = _issueDate;\n    // owner mandatory\n    var (errorCode,) = addOwner(_number, _ownerNumber0, _ownerHash0);\n    if (errorCode != ErrorCodes.SUCCESS) return (errorCode, -1);\n    // LH optional\n    if (_lienHolderNumber0 != 0) {\n      addLienHolder(_number, _lienHolderNumber0, _lienHolderHash0);\n    }\n    // snapshot\n    addSnapshotUint(setTitleEvent, _number);\n    return (ErrorCodes.SUCCESS, ++updateCounter);\n  }\n\n  function addLienHolder(\n    uint _titleNumber, \n    uint _number, \n    string _hash\n  ) public returns (ErrorCodes, int) {\n    // validate\n    if (_number == 0 || bytes(_hash).length == 0) {\n      return (ErrorCodes.ERROR, -1);\n    }\n    // validate the titleNumber same as Vehicle TitleNumber\n    if (_titleNumber != number) {\n      return (ErrorCodes.ERROR, -1);\n    }\n    // if pendingAddLienHolderNumber exists then shall match w/ pending lienHolder number\n    if (pendingAddLienHolderNumber != -1 && int(_number) != pendingAddLienHolderNumber) {\n      return (ErrorCodes.NOT_FOUND, -1);\n    }\n    // Max limit of lienHolders is 4\n    if (lienHolders.length >= lhMaxLimit) {\n      return (ErrorCodes.ERROR, -1);\n    }\n    LienHolder memory lienHolder = LienHolder(_number, _hash);\n    lienHolders.push(lienHolder);\n    // reset pending addLienHolder Number\n    pendingAddLienHolderNumber = -1;\n    // snapshot\n    addSnapshotUint(addLienHolderEvent, _number);\n    return (ErrorCodes.SUCCESS, ++updateCounter);\n  }\n\n  // function to set pending addLienHolder number\n  function pendingAddLienHolder(uint _number) returns(ErrorCodes, int) {\n    // return error if pendingLienHolder pkaceholder number is not zero\n    if (pendingAddLienHolderNumber != -1 ) {\n      return(ErrorCodes.EXISTS, -1);\n    }\n    // incoming pending LienHolder Number can't be zero\n    if (_number == 0) {\n      return(ErrorCodes.ERROR, -1);\n    }\n    // set pending addLienHolder Number\n    pendingAddLienHolderNumber = int(_number);\n    //snapshot\n    addSnapshotUint(pendingAddLienHolderEvent, _number);\n    return(ErrorCodes.SUCCESS, ++updateCounter);\n  }\n\n  function addOwner(\n    uint _titleNumber, \n    uint _number, \n    string _hash\n  ) public returns (ErrorCodes, int) {\n    // validate\n    var errorCode =  validateOwner(_number, _hash) ;\n    if (errorCode != ErrorCodes.SUCCESS) {\n      return (errorCode, -1);\n    }\n    if (_number == 0 || bytes(_hash).length == 0) {\n      return (ErrorCodes.ERROR, -1);\n    }\n    // validate the titleNumber same as Vehicle TitleNumber\n    if (_titleNumber != number) {\n      return (ErrorCodes.ERROR, -1);\n    }\n\n    // Max limit of owners is 2\n    if (owners.length >= ownerMaxLimit) {\n      return (ErrorCodes.ERROR, -1);\n    }\n    Owner memory owner = Owner(_number, _hash);\n    owners.push(owner);\n    // snapshot\n    addSnapshotUint(addOwnerEvent, _number);\n    return (ErrorCodes.SUCCESS, ++updateCounter);\n  }\n\n  function validateOwner(\n    uint _number, \n    string _hash\n  ) public returns (ErrorCodes) {\n    // validate\n    if (_number == 0  || bytes(_hash).length == 0) {\n      return (ErrorCodes.ERROR);\n    }\n    return (ErrorCodes.SUCCESS);\n  }\n\n  function updateVehicle(\n    string _vtype, \n    string _year, \n    string _make, \n    string _model, \n    string _style, \n    string _color, \n    uint _number\n  ) public returns (ErrorCodes, int)\n  {\n    if (bytes(_vtype).length != 0) {\n      vtype = _vtype;\n      // add snapshot\n      addSnapshot(updateVehicleTypeEvent, _vtype);\n    }\n    if (bytes(_year).length != 0) {\n      year = _year;\n      // add snapshot\n      addSnapshot(updateVehicleYearEvent, _year);\n    }\n    if (bytes(_make).length != 0) {\n      make = _make;\n      // add snapshot\n      addSnapshot(updateVehicleMakeEvent, _make);\n    }\n    if (bytes(_model).length != 0) {\n      model = _model;\n      // add snapshot\n      addSnapshot(updateVehicleModelEvent, _model);\n    }\n    if (bytes(_style).length != 0) {\n      style = _style;\n      // add snapshot\n      addSnapshot(updateVehicleStyleEvent, _style);\n    }\n    if (bytes(_color).length != 0) {\n      color = _color;\n      // add snapshot\n      addSnapshot(updateVehicleColorEvent, _color);\n    }\n    if (_number != 0) {\n      number = _number;\n      // add snapshot\n      addSnapshotUint(updateVehicleNumberEvent, _number);\n    }\n\n    return(ErrorCodes.SUCCESS, ++updateCounter);\n  }\n\n  function updateReasons( string _reasons) public returns (ErrorCodes, int) {\n    addSnapshot(updateReasonsEvent, _reasons);\n    return (ErrorCodes.SUCCESS, ++updateCounter);\n  }\n\n /**\n  * removeLienHolder() function to remove lienHolder by given Index.\n  * It also validates following condition:\n  * - Given index should not be greator than or equal to lienHolderIndex Array length\n  * @param _index (uint) - lienHolders array index\n  * @return ErrorCodes: The Error code\n  */\n  function removeLienHolder(uint _titleNumber, uint _index) public returns (ErrorCodes, int) {\n    // validate the titleNumber same as Vehicle TitleNumber\n    if (_titleNumber != number) {\n      return (ErrorCodes.ERROR, -1);\n    }\n\n    // if pendingRemoveLienHolderIndex exists then shall match index w/ pending lienHolder index\n    if (pendingRemoveLienHolderIndex != -1 && int(_index) != pendingRemoveLienHolderIndex) {\n      return (ErrorCodes.NOT_FOUND, -1);\n    }\n    if (_index >= lienHolders.length) {\n      return(ErrorCodes.ERROR, -1);\n    }\n    // To delete the index from lienHolderIndex array\n    for (uint lhi = _index; lhi<lienHolders.length-1; lhi++) {\n      // shift the indexes towards left by 1\n      lienHolders[lhi] = lienHolders[lhi+1];\n      }\n    // finally delete the last element of the lienHolderIndex array\n    delete lienHolders[lienHolders.length-1];\n    lienHolders.length--;\n    // reset pendingRemoveLienHolderIndex after success Removal of Lienholder\n    pendingRemoveLienHolderIndex = -1;\n    // snapshot\n    addSnapshotUint(removeLienHolderEvent, _index);\n    return (ErrorCodes.SUCCESS, ++updateCounter);\n  }\n\n  // function to set pending removeLienHolder Index\n  function pendingRemoveLienHolder(uint _index) returns(ErrorCodes, int) {\n    // return exists error if already pendingLienHolder is present\n    if (pendingRemoveLienHolderIndex != -1 ) {\n      return(ErrorCodes.EXISTS, -1);\n    }\n    // set pending lienHolder Index\n    pendingRemoveLienHolderIndex = int(_index);\n    //snapshot\n    addSnapshotUint(pendingRemoveLienHolderEvent, _index);\n    return(ErrorCodes.SUCCESS, ++updateCounter);\n  }\n  /**\n  * removeOwner() function to remove Owner by given Index.\n  * It also validates following condition:\n  * - Given index should not be greator than or equal to Owners Array length\n  * @param _index (uint) - owners array index\n  * @return ErrorCodes: The Error code\n  */\n  function removeOwner( uint _titleNumber, uint _index) public returns (ErrorCodes, int) {\n    // validate the titleNumber same as Vehicle TitleNumber\n    if (_titleNumber != number) {\n      return (ErrorCodes.ERROR, -1);\n    }\n    // validate array index\n    if (_index >= owners.length) {\n      return(ErrorCodes.ERROR, -1);\n    }\n    // To delete the index from owners array\n    for (uint owner = _index; owner<owners.length-1; owner++) {\n      // shift the values towards left by 1\n      owners[owner] = owners[owner+1];\n      }\n    // finally delete the last element of the owners array\n    delete owners[owners.length-1];\n    owners.length--;\n    // snapshot\n    addSnapshotUint(removeOwnerEvent, _index);\n    return (ErrorCodes.SUCCESS, ++updateCounter);\n  }\n\n  //========================================================\n  // Snapshot history\n  //========================================================\n  struct vehicleSnapshot {\n    // meta\n    uint timestamp;\n    string eventType;\n    string eventData;\n    // details\n    string vin;\n    string vtype;\n    string year;\n    string make;\n    string model;\n    string style;\n    string color;\n    // title details\n    uint number;\n    uint issueDate;\n    // pending details\n    int pendingAddLienHolderNumber;\n    int pendingRemoveLienHolderIndex;\n  }\n\n  vehicleSnapshot[] vehicleHistory;\n  Owner[][] ownerHistory;\n  LienHolder[][] lienHolderHistory;\n\n  function addSnapshot(string _eventType, string _eventData) private {\n    vehicleSnapshot memory snapshot = vehicleSnapshot(\n      // header\n      block.timestamp, \n      _eventType, \n      _eventData, \n      // vehicle details\n      vin, \n      vtype, \n      year, \n      make, \n      model, \n      style, \n      color, \n      // title details\n      number, \n      issueDate, \n      // pending\n      pendingAddLienHolderNumber, \n      pendingRemoveLienHolderIndex\n    );\n\n    // save all\n    vehicleHistory.push(snapshot);\n    ownerHistory.push(owners);\n    lienHolderHistory.push(lienHolders);\n  }\n\n  function addSnapshotUint(string _eventType, uint _eventData) private {\n    string memory eventDataString = uintToString(_eventData);\n    addSnapshot(_eventType, eventDataString);\n  }\n}\n\n\n"]


data AccountInfo = NonContract Address Integer
                 | ContractNoStorage Address Integer SHA
                 | ContractWithStorage Address Integer SHA [(Word256, Word256)]
   deriving (Show, Eq)

$(deriveJSON defaultOptions{sumEncoding = AT.UntaggedValue} ''AccountInfo)

data GenesisInfo =
  GenesisInfo {
    genesisInfoParentHash       :: SHA,
    genesisInfoUnclesHash       :: SHA,
    genesisInfoCoinbase         :: Address,
    genesisInfoAccountInfo      :: [AccountInfo],
    genesisInfoTransactionsRoot :: StateRoot,
    genesisInfoReceiptsRoot     :: StateRoot,
    genesisInfoLogBloom         :: B.ByteString,
    genesisInfoDifficulty       :: Integer,
    genesisInfoNumber           :: Integer,
    genesisInfoGasLimit         :: Integer,
    genesisInfoGasUsed          :: Integer,
    genesisInfoTimestamp        :: UTCTime,
    genesisInfoExtraData        :: Integer,
    genesisInfoMixHash          :: SHA,
    genesisInfoNonce            :: Word64
} deriving (Show, Eq, Generic)

nullStateRoot :: StateRoot
nullStateRoot = StateRoot . fst . B16.decode $
    "56e81f171bcc55a6ff8345e692c0f86e5b48e01b996cadc001622fb5e363b421"
defaultGenesisInfo :: GenesisInfo
defaultGenesisInfo =
  GenesisInfo {
    genesisInfoParentHash = SHA 0,
    genesisInfoUnclesHash = SHA 13478047122767188135818125966132228187941283477090363246179690878162135454535,
    genesisInfoCoinbase = Address 0,
    genesisInfoAccountInfo = [],
    genesisInfoTransactionsRoot = nullStateRoot,
    genesisInfoReceiptsRoot = nullStateRoot,
    genesisInfoLogBloom = B.replicate 512 0,
    genesisInfoDifficulty = 131072,
    genesisInfoNumber = 0,
    genesisInfoGasLimit = 3141592,
    genesisInfoGasUsed = 0,
    genesisInfoTimestamp = read "1970-01-01 00:00:00 UTC"  ::  UTCTime,
    genesisInfoExtraData = 0,
    genesisInfoMixHash = SHA 0,
    genesisInfoNonce = 42
}

instance FromJSON GenesisInfo where
  parseJSON (Object o) =
    GenesisInfo <$>
    o .: "parentHash" <*>
    o .: "unclesHash" <*>
    o .: "coinbase" <*>
    o .: "accountInfo" <*>
    o .: "transactionRoot" <*>
    o .: "receiptsRoot" <*>
    o .: "logBloom" <*>
    o .: "difficulty" <*>
    o .: "number" <*>
    o .: "gasLimit" <*>
    o .: "gasUsed" <*>
    o .: "timestamp" <*>
    o .: "extraData" <*>
    o .: "mixHash" <*>
    o .: "nonce"
  parseJSON x = error $ "couldn't parse JSON for genesis block: " ++ show x

instance ToJSON GenesisInfo where
  toEncoding x = pairs (
      "parentHash" .= genesisInfoParentHash x <>
      "unclesHash" .= genesisInfoUnclesHash x <>
      "coinbase" .= genesisInfoCoinbase x <>
      "transactionRoot" .= genesisInfoTransactionsRoot x <>
      "receiptsRoot" .= genesisInfoReceiptsRoot x <>
      "logBloom" .= genesisInfoLogBloom x <>
      "difficulty" .= genesisInfoDifficulty x <>
      "number" .= genesisInfoNumber x <>
      "gasLimit" .= genesisInfoGasLimit x <>
      "gasUsed" .= genesisInfoGasUsed x <>
      "timestamp" .= genesisInfoTimestamp x <>
      "extraData" .= genesisInfoExtraData x <>
      "mixHash" .= genesisInfoMixHash x <>
      "nonce" .= genesisInfoNonce x <>
      "accountInfo" .= genesisInfoAccountInfo x
    )
